import os
import mysql.connector as mc
from contextlib import suppress # https://stackoverflow.com/questions/1802467/try-except-finally-syntax-in-python
from argparse import ArgumentParser

# Connect to MySQL DB and create the necessary table if not present, else drop it.
db = 'mydb'
table_name = 'students'


def connect():
    """ Connect to database using MySQL Connector """

    return mc.connect(host='127.0.0.1',
                      user='user',
                      password='<PASSWORD>',
                      database=db)

@suppress(Exception) # If there are already students in the table drop and re-create it.
def create_table():
    """ Connect to MySQL DB, create the necessary table if not present
        else drop it and re-create it."""

    db = connect()
    
    cursor = db.cursor()  # Get a cursor object to execute queries with

    # Create table if not exists using LOAD DATA INFILE statements.
    cursor.execute("CREATE TABLE IF NOT EXISTS {0} (name VARCHAR(128), roll_number INTEGER)".format(table_name))

    # If the file already exists append the data onto it.
    # Drop and re-create table and append the new data to it.
    cursor.execute('DROP TABLE {}'.format(table_name))
    cursor.execute("CREATE TABLE {0} (name VARCHAR(128), roll_number INTEGER)".format(table_name))

    # Return the connection object to callers
    return db

def execute_sql():
    
    ''' Connect to database, create a cursor and insert into table'''
    
    # Open the file
    with open('input.txt', 'r') as inFile:

        # Load data into table
        sql = "LOAD DATA INFILE '{}' INTO TABLE {0}".format(inFile.name ,table_name)
        
        db = connect()

        # Cursor is a context manager that maintains a list of statements 
        cursor = db.cursor()

        with suppress(Exception):
            print("Table already exists and will be overwritten")

        try:
            cursor.execute(sql)

        except Exception as e: 
            print(e)

        else :

            print ("Data has been loaded into the table successfully.")
            
        finally:
            # Close the cursor, free resources, commit, close DB connection
            db.commit()
            cursor.close()
            db.close()

def main():
    
    parser = ArgumentParser('Python MySQL ETL script to use LOAD DATA INFILE for bulk imports')
    parser.add_argument("-f", "--file" , required=True)
    args = parser.parse_args()

    create_table() 
    execute_sql()


if __name__ == "__main__":
    
    main()